text:
Histograms

Codepenguins |&gt;
  drop_na(
    flipper_length_mm,
    species
  ) |&gt;
  ggplot(
    aes(
      x = flipper_length_mm,
      fill = species
    )
  ) +
  geom_histogram(
    bins = 30,
    alpha = 0.5,
    position = "identity"
  ) +
  scale_fill_brand_d() +
  labs(
    x = "Flipper Length (mm)",
    y = "Frequency",
    fill = "Species"
  )

Boxplots

Codepenguins |&gt;
  drop_na(
    bill_length_mm,
    species
  ) |&gt;
  ggplot(
    aes(
      x = species,
      y = bill_length_mm,
      fill = species
    )
  ) +
  geom_boxplot(
    outlier.color = get_brand_color("dark-red")
  ) +
  geom_jitter(
    width = 0.2,
    alpha = 0.1
  ) +
  scale_fill_brand_d(alpha = 0.7) +
  labs(
    x = "Species",
    y = "Bill Length (mm)",
    fill = "Species"
  )

Density

Codepenguins |&gt;
  drop_na(
    flipper_length_mm,
    species
  ) |&gt;
  ggplot(
    aes(
      x = flipper_length_mm,
      fill = species
    )
  ) +
  geom_density(
    alpha = 0.5,
    position = "identity"
  ) +
  scale_fill_brand_d() +
  labs(
    x = "Flipper Length (mm)",
    y = "Density",
    fill = "Species"
  ) +
  theme(
    legend.position = "none"
  )
